import React from 'react';
import './Contact.css';

const Contact = () => {
  return (
    <section className="contact">
      <h2>Get In Touch</h2>
      <p>Email: <a href="mailto:jayaisurusamarakoon7@gmail.com">jayaisurusamarakoon7@gmail.com</a></p>
      <p>Phone: 0719011933</p>
      <p>LinkedIn: <a href="https://linkedin.com/in/jayaisuru-samarakoon-8665b2313" target="_blank" rel="noopener noreferrer">linkedin.com/in/jayaisuru-samarakoon-8665b2313</a></p>
      <p>GitHub: <a href="https://github.com/IT22569486" target="_blank" rel="noopener noreferrer">github.com/IT22569486</a></p>
    </section>
  );
}

export default Contact;
